import java.util.Arrays;

public int minimumXorSum(int[] nums1, int[] nums2) {
    Arrays.sort(nums2);
    int xorSum = 0;
    for (int i = 0; i < nums1.length; i++) {
        xorSum += nums1[i] ^ nums2[i];
    }
    return xorSum;
}
```

